var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"정말 엄청 크고 으리으리한 유람선이네......","JPN":"大きくて立派な遊覧船だ……","ENG":"This cruise is so big and luxurious-looking...","TWN":"真是艘好大好壯觀的遊輪……"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 초호화 크루즈에 타게 된다고?","JPN":"超豪華クルーズ船に乗れるの？","ENG":"I'll be cruising on a super-luxurious ship?","TWN":"我可以坐超豪華的遊輪？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다, 미나 양. 리플레이서 사건을 해결한 공로로 사장님께서 주신 특별 휴가도 함께 말이죠.","JPN":"そうです。リプレイサー事件を解決した功労として、社長が特別休暇とクルーズ船を用意してくださいました。","ENG":"That's right, Mina. On a special vacation awarded to you by the Boss for solving the Replacer case.","TWN":"是的，米娜小姐。作為解決克隆集團事件的獎勵，老闆還給了妳特別假期。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 동안 힘들었던 만큼 푹 쉬고 오시면 되겠군요.","JPN":"今まで大変だった分、ゆっくり休んできてください。","ENG":"You've worked hard. You deserve this.","TWN":"這段時間妳一定很累吧，就趁這個機會去好好休息一下。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저, 정말이야? 와, 이런 건 전혀 기대도 안 했었는데 회사 사정이 좋아졌나 보네.","JPN":"ほ、本当に？　こんなの全然期待してなかったけど、結構儲かってるんだね。","ENG":"A-are you sure? Wow, I never expected anything like this. Our company must be doing better than I thought.","TWN":"真、真的嗎？我完全沒有期待過這種事，看來公司情況有所好轉了呢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"축제가 있는 섬으로 가는 배라고 했지? 그럼 수영복이라도 새로 사야 하려나?","JPN":"お祭りが開かれる島に向かうって言ってたし、水着を買っていった方がいいかな？","ENG":"So, a ship to a festival island, huh? Maybe I need to buy a new swimsuit.","TWN":"會到一個島上參加慶典嗎？那我是不是該買件新的泳裝？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"헤헤. 어쨌든 사장님께 고맙다고 전해줘.","JPN":"ヘヘッ、とにかく社長にお礼を言っておいて。","ENG":"Heh heh. Anyway, please thank the Boss for me.","TWN":"嘿嘿，不管怎樣，都替我謝謝老闆。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼요, 잘 다녀오세요.","JPN":"わかりました。それではお気をつけて。","ENG":"Sure thing. Enjoy your vacation.","TWN":"好的，祝妳一路順風。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 지난 번에 사장님께서 채굴 의뢰가 너무 안 들어와서 일용직 갑판 청소 의뢰라도 받아야 할 것 같다고 혼잣말을 하시던데......","JPN":"そういえば、この前社長が採掘の依頼が全然入ってこないから、\\n日雇いで甲板掃除の依頼でも引き受けようかとか何とかって言ってたような……","ENG":"Come to think of it, I happened to overhear the Boss debating with himself whether or not we should start taking deck-cleaning jobs because we weren't getting enough mining jobs.","TWN":"話說回來，上次我聽老闆自言自語，說因為很久沒有接到採礦委託，所以得接一些短期的甲板清掃委託呢……"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시끄러워요, 시윤 군.","JPN":"黙りなさい。","ENG":"Hush, Shiyoon.","TWN":"你很吵喔，時雲君。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회사 보안 정책 위반으로 감봉 3개월을 당하기 싫으면 입다무세요.","JPN":"会社のセキュリティポリシー違反で減給3か月になりたくなかったら、その口を閉じた方がいいですよ。","ENG":"You'll keep your mouth shut, or you'll get a pay cut for the next three months for violating the company's security policy.","TWN":"如果你不想因為違反公司保密政策，被罰款三個月薪資的話就閉嘴。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"......휴가라고 하더니.","JPN":"……休暇って言ってたくせに。","ENG":"A vacation, my butt.","TWN":"……還說什麼休假。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"내 팔자가 그럼 그렇지.","JPN":"まぁ、やけにうまい話だと思ったよ。","ENG":"I knew this was too good to be true.","TWN":"這就是我的人生。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"어이, 신참! 어디서 농땡이를 피우고 있나?! 구석구석 꼼꼼히 청소하도록!","JPN":"おい、新入り！　なにサボってたんだ？　隅々まで綺麗に掃除しろよな！","ENG":"Hey, rookie! Stop dilly-dallying and clean each and every nook and cranny!","TWN":"喂，新人！別偷懶！給我好好打掃！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"네! 네! 선장님!","JPN":"はいっ、船長！","ENG":"Aye, aye, Captain!","TWN":"是！是！船長！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"야, 야, 날 선장이라 부르지 말랬지! 선장님께서 들으시면 어쩌려고......","JPN":"おいおい、俺のことを船長って呼ぶな！　船長に聞かれたらどうすんだ……","ENG":"Hey, I told you not to call me that! The real Captain would be upset if he heard that.","TWN":"喂喂，說了別叫我船長！萬一被船長聽見了那可怎麼辦……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"그리고 넌 청소부가 아니라 경비라고 몇 번을 말해!","JPN":"それにお前は清掃じゃなくて警備だって、何回言えばわかるんだ！","ENG":"Also, how many times do I have to tell you that you're not a cleaner, but a security guard?","TWN":"還有，我說過很多次了，妳不是清潔工，而是警衛！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"에이, 경비라곤 하지만 아직 딱히 할 일도 없으니까~ 겸사겸사 청소도 거드는 거지~","JPN":"だって警備って言われても特にやることないし～。ついでに掃除でもしようかなって。","ENG":"Come on, I don't have much to do now. I might as well help clean.","TWN":"哎，不過雖說是警衛，但也沒什麼事做呀～所以就順便幫忙打掃打掃嘛～"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"하아...... 이렇게 걸레질이나 할 줄 알았으면 수영복은 뭐 하러 입었담.","JPN":"はぁ……雑巾がけをさせられるって知ってたら、水着なんて着なかったのに……","ENG":"*Sigh* I never thought I'd be mopping in this swimsuit when I first wore it.","TWN":"唉……早知道是過來擦地板的，我穿泳裝幹嘛。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L34_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"신참! 한숨으로 바닥 꺼트릴 생각 말고 이쪽에 선객들이 남기고 간 쓰레기나 치워!","JPN":"新入り！　ため息なんかついてる暇があったら、ここのゴミを片づけろ！","ENG":"Rookie! Stop sighing so loudly and clean up after the passengers over here!","TWN":"新人！別唉聲歎氣的，快來這裡打掃乘客們留下的垃圾！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"네에! 갑니다! 가요!","JPN":"はい、今行きます！","ENG":"Aye! I'm coming, I'm coming!","TWN":"是！我這就去！這就去！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"어머? 유미나씨 아닌가요? 이런 곳에서 또 보네요.","JPN":"あら、ヤナギ・ミナさん？　こんなところでお会いするなんて、奇遇ですね？","ENG":"Mm? Mina? What a pleasant surprise!","TWN":"哎呀？劉米娜小姐？沒想到會在這裡遇見妳。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"음? 어, 어라?","JPN":"うん？","ENG":"Mm? Err, err?","TWN":"嗯？咦，咦？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"......아! 당신은 발렌타인 때 만났던......","JPN":"あっ……！　あなたはバレンタインの時に会った……","ENG":"Ah! You're from Valentine's Day...","TWN":"……啊！妳是情人節那天的……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"엘리자베스 팬드래건입니다. 다시 만나서 반가워요.","JPN":"エリザベス・ペンドラゴンです。またお会いできて嬉しいですわ。","ENG":"Elizabeth Pendragon. It's good to see you again.","TWN":"我是伊莉莎白·潘德拉貢，很高興再見到妳。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"듣자 하니 지난 번 리플레이서 사태에서도 많이 활약했다고요?","JPN":"聞くところによると、この前のリプレイサー事件でも大活躍だったそうですね？","ENG":"I've heard you were instrumental in solving the Replacer incident.","TWN":"聽說妳在克隆集團事件中表現得非常活躍？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"발렌타인 때도 그렇고 실력이 쓸만해서 기억하고 있어요.","JPN":"バレンタインの時もそうでしたけど、とても実力のあるお方だったのでよく覚えています。","ENG":"I remembered you because you were also pretty impressive on Valentine's Day.","TWN":"上次情人節的時候，我就注意到了妳的實力。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"하하...... 기억해주고 있다니, 그거 고맙네.","JPN":"はは……覚えていてくれたなんて、それはありがたいね。","ENG":"Hah hah. Thank you for remembering me.","TWN":"哈哈……妳還記得啊，謝謝。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"그런데 당신도 블루로즈 섬에 가는 거야?","JPN":"ところで、あなたもブルーローズ島に行くの？","ENG":"By the way, are you also going to Blue Rose Island?","TWN":"不過妳也要去藍玫瑰島嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"네, 전 어렸을 때부터 매년 블루로즈 섬의 축제에 참가해 왔으니까요.","JPN":"はい、私は子供の頃から毎年ブルーローズ祭に参加していたので。","ENG":"Yes, I've been going to the festival there every year since I was young.","TWN":"是的，我每年都會參加藍玫瑰島的慶典。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"마침 축제기간이기도 하고 또 최근에 저희 프리드웬 기관에 들어온 어떤 <color=#83dcb7>물벼룩</color>의 교육 때문에 골치가 좀 아파서 기분 전환이나 할 겸 온 거죠.","JPN":"ちょうどお祭りの期間でもありますし、最近私たちのプリドウェン機関に入ってきたある<color=#83dcb7>ミジンコ</color>の教育のせいで、頭が痛くて気分転換も兼ねて来たんです。","ENG":"This time, I'm not going there just for the festival, though. I desperately need a change of air because of this stupid <color=#83dcb7>Water Flea</color> that recently has joined my organization, the Prydwen Institution.","TWN":"正好現在是慶典期間，而且最近我為了教育一個剛進入普利多溫機關的<color=#83dcb7>水蚤</color>傷透了腦筋，所以出來透透氣。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"그거 부럽네. 난 어떤 악덕 사장 덕분에 갑판 청소나 해야 하는 신세거든.","JPN":"羨ましいな。私は悪徳社長のせいで、甲板の掃除をさせられてるよ。","ENG":"I'm envious of you. I'm here to clean the deck, thanks to my evil boss.","TWN":"好羨慕喔，我是因為一個缺德老闆，才來這裡打掃甲板的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"흐음, 그럼 제가 미나 양에게 초대권을 한 장 선물해 드려도 될까요?","JPN":"でしたら、私がミナさんに招待券をプレゼントしてもよろしいでしょうか？","ENG":"Hm, then perhaps I could give you an invitation to the island.","TWN":"哦，那我送米娜小姐一張邀請函吧，怎麼樣？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"이 여객선의 특실 숙박권까지 포함해서요.","JPN":"この旅客船の特別室宿泊券も含まれていますわ。","ENG":"Plus a special cabin on the ship.","TWN":"包括遊輪的豪華住宿券。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"저, 정말이야? 엄청 비쌀 텐데...... 그런 걸 나한테 줘도 괜찮은 거야?","JPN":"ほ、本当にいいの？　すごく高そうだけど……そんなものを私に？","ENG":"A-are you serious? But they can't be cheap. Are you sure you can give them to me?","TWN":"真、真的嗎？這應該很貴吧……送給我真的沒關係嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"물론이에요. 리플레이서 사태의 영웅인 미나 양에겐 저희가 빚을 진 거나 마찬가지니까요.","JPN":"もちろんです。リプレイサー事件の英雄であるミナさんには、私たちが借りを作ってしまったも同然ですから。","ENG":"Sure. You're the hero of the Replacer incident. We actually owe you one.","TWN":"當然，米娜小姐是克隆集團事件的英雄，相當於我們欠妳一個大人情。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"같이 세계를 수호하는 프리드웬 기관의 수장으로서 미나 양에게 그 정도의 감사 표시는 할 수 있답니다.","JPN":"同じく世界を守護するプリドウェン機関の首長として、ミナさんにその程度のお礼はすべきかと思いますわ。","ENG":"As the leader of the Prydwen Institution and a defender of the world peace, I'd like to thank you for your heroism.","TWN":"作為共同守護世界的普利多溫機關長，我想用這點心意來表達感謝。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"고, 고마워! 이 은혜는 잊지 않을게!!","JPN":"あ、ありがとう！　この恩は絶対忘れないよ！","ENG":"Th-thanks! I'll never forget this!","TWN":"謝、謝謝妳！我不會忘記這份恩情的！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아하하, 비켜라, 비켜. 필멸자들! 왕의 행차시다!","JPN":"アハハ、退け！　退くのじゃ、虫けらども！　王のお通りじゃ！","ENG":"Ah hah hah! Get out of my way, mortals! Here comes the Lord!","TWN":"哈哈，讓開，讓開，必滅者！你們的王駕臨了！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"그러고 보니 그 아이들도 귀여운 구석이 있지 않느냐? 짐이 호텔에서 쉬는 동안 이런 여흥을 다 준비하고 말이다.","JPN":"そういえば、あやつらにも可愛いところがあるじゃないか？　妾がホテルで休んでる間、こんな余興を準備しておったとはのう。","ENG":"Come to think of it, those kids are pretty cute. They've arranged transport and accommodation for me while I was resting at the hotel.","TWN":"那些孩子也挺可愛的不是嗎？趁著朕在飯店休息的時候，居然還準備了餘興節目。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇습니다. 허나 주인님의 덕과 은혜에 비하면 하찮을 뿐이지요.","JPN":"そうですね。しかし、ロザリア様の恩徳に比べれば取りに足りません。","ENG":"Yes, Mistress. But this is nothing compared to your greatness and benevolence.","TWN":"您說得對，但和主人的恩德相比，這些根本就微不足道。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인과 일행들도 주인님께 봉사하는 것을 기쁘게 생각할 것입니다.","JPN":"依頼人と一行たちも、ロザリア様にご奉仕できることを光栄に思っていることでしょう。","ENG":"I'm sure our client and the others are only happy to serve you.","TWN":"委託人和其他人也一定也很榮幸能為主人服務的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"오빠...... 머리 나쁜 내가 봐도 완전 간신배 같아.","JPN":"兄さん……頭の悪いアタシが見ても極悪非道の家来みたいだ。","ENG":"Doma, I'm not smart, but even I can tell you're brown-nosing right now.","TWN":"哥哥……連我這種腦袋不好的人也覺得你是個奸臣。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"뭐, 뭐야 저 사람들? 어느 나라 왕족이라도 되나?","JPN":"な、何？　あいつら……どっかの国の王族なの？","ENG":"W-what are they doing? Is she a member of some royal family?","TWN":"那、那些人是誰？是哪個國家的王族嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"이건 또 뭐냐. 감히 짐의 행차를 가로막다니......","JPN":"これはまた何じゃ、妾の行く手を阻むとは……","ENG":"What's this? Who dares get in my way?","TWN":"這又是什麼東西，竟敢阻攔朕。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"왜 그래? 주인님. 거슬리는 녀석이라면 내가 박살내 버릴까?","JPN":"どうかしましたか？　目障りなやつがいれば、アタシがぶっ壊しましょうか？","ENG":"What's wrong, Mistress? Do you want me to get rid of her for you?","TWN":"怎麼了？主人，要不要我幫妳解決掉？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아, 아니...... 여기선 돌아가도록 하자.","JPN":"いや……ここは引き返すとしよう。","ENG":"No, don't. Let's just go back.","TWN":"不、不……還是回去吧。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"하필 여기서 마주칠 줄은 몰랐는데, 곤란하군.","JPN":"よりにもよってここで出くわすとはな、困ったものじゃ。","ENG":"I can't believe I met her here. This is not good.","TWN":"沒想到偏偏在這裡遇到，真是困擾啊。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"엥? 한 주먹거리도 안 되어 보이는데...... 그렇게 쎈 녀석이야?","JPN":"うん？　ひ弱そうに見えるけど……そんなに強いのか？","ENG":"Huh? She doesn't look strong at all. Is she?","TWN":"什麼？她看起來不堪一擊呀……有那麼厲害嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아니 그렇다기보단 녀석에게 엮여있는 다른 존재가 꽤나 껄끄럽달까......","JPN":"いや、あやつと関わりのある他の存在が厄介というか……","ENG":"This is not about her. It's about someone else who's connected to her.","TWN":"不，是因為和她有關的另一個傢伙比較棘手……"},"stage":{"bg":"BLACK","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"에잇! 몰라! 몰라! 그냥 시키면 시키는 대로 해!","JPN":"ええいっ！　なぜ妾が説明をせねばならぬのじゃ！","ENG":"Gah! Whatever! Just do as I say!","TWN":"哎！不管啦！不管啦！你只要照我說的做就行了！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 알겠어! 유턴 유턴!","JPN":"わ、わかったよ！　Ｕターン！","ENG":"Oh, okay. Let's make a U-turn! U-turn!","TWN":"啊，知道了！調頭，調頭！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"뭐야...... 이상한 사람들이네.","JPN":"何？　変な人たち……","ENG":"What was that? Such weirdoes!","TWN":"搞什麼……一群怪人。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께서 말씀하신 거대한 배로군요. 여기에 그 불길한 기운이 있는 겁니까?","JPN":"当主、とても大きな船ですね。ここから不吉な気を感じるんですか？","ENG":"This is the giant ship you told me about. Is it where the ominous energy was detected?","TWN":"看來這就是家主您說的大船了，那個不祥的氣息是來自這裡嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 바람이 이 배에서 불길함이 느껴진다고 속삭여주고 있어요.","JPN":"はい、風がこの船から不吉な気を感じると囁いています。","ENG":"Yes, the wind is whispering to me that there's something ominous about this ship.","TWN":"是的，風兒告訴我這艘船上能感受到不祥的氣息。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유! 곧 출발할 테니 어서 배에 오르도록 하죠.","JPN":"千冬！　もうすぐ出発するようですので、急いで乗りましょう。","ENG":"Chifuyu, the ship is about to take off. Let's get on it.","TWN":"千冬！馬上就要出發了，快上船。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 아무리 봉인을 위해서라곤 해도...... 이렇게 허가 없이 무임승선을 해도 괜찮겠습니까?","JPN":"しかし、いくら封印のためとはいえ……許可なく無賃乗船をしてもいいのでしょうか？","ENG":"But even if we're here to seal the energy, are you sure we can get on the ship without paying our fare?","TWN":"雖說是為了封印……但這樣不買票就上船真的好嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 거라면 걱정 마세요. 승선에 필요한 초대장이라면 제가 가지고 있거든요.","JPN":"それは心配ありません。乗船に必要な招待状でしたら、私が持っています。","ENG":"Don't worry about that. I have the invitations we need to get on this ship.","TWN":"這點不用擔心，因為我身上帶著搭船需要的邀請函。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 그런 걸 대체 어떻게 구하신 건지......?","JPN":"え？　そんなものをいったいどうやって手に入れたのですか……？","ENG":"Pardon? Where did you get them?","TWN":"什麼？您是從哪裡拿到的……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"으흠! 자초지종은 나중에! 따라오기나 해요!","JPN":"ゴホン！　それは後で説明しましょう。ひとまずついて来てください。","ENG":"Ahem! I'll tell you later. Just follow me for now.","TWN":"唉唷！這個以後再說！快跟我來！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아앗, 당주님! 그렇게 손을 끄시면 제대로 호위를 할 수가......","JPN":"ああっ、当主！　そのように手を引かれたら、まともに護衛することが……","ENG":"Ah, Lady Nanahara! Please, let go off my hand. I can't protect you...","TWN":"啊啊，家主！您抓著我的手就不能好好保護您了……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"계장님! 지금 대체 어디 계신 거에요?!","JPN":"係長！　どこにいるんですか！？","ENG":"Chief! Where the hell are you right now?","TWN":"科長，妳到底在什麼地方？！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"어...... 그러니까 블루로즈로 가는 여객선을 타고 있는데......","JPN":"あぁ……えっと、ブルーローズに行く旅客船に乗っている……","ENG":"Err... On a ferry to Blue Rose?","TWN":"呃……我在開往藍玫瑰的遊輪上……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"브, 블루로즈?!","JPN":"ブ、ブルーローズ！？","ENG":"B-Blue Rose?!","TWN":"藍、藍玫瑰？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"동사무소 워크샵 장소를 물색하라고 해놨더니 무슨 블루로즈에요!","JPN":"役所のワークショップの場所を探してほしいとは言いましたが、どうしてブルーローズに！？","ENG":"I sent you to look for a place to hold our workshop, not Blue Rose!","TWN":"我不是叫妳去找區公所團旅的場所嗎，說什麼藍玫瑰！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"거기 엄청 비싼 휴양지잖아? 우리 예산으로 가당키나 해요?!","JPN":"しかもそこってすごく高いリゾート地じゃないですか？　私たちの予算じゃ到底行けませんよ！","ENG":"That's a ridiculously expensive resort. We don't have a budget like that!","TWN":"那裡可是超貴的度假勝地，我們哪有那麼多預算？！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"아니, 그, 그게...... 답사 중에 어떤 아이들을 도와줄 일이 있었는데 그 대신 고맙다고 초대권을 선물 받는 바람에......","JPN":"いや、それが……リサーチ中にある人たちを助けたら、お礼にって招待券をもらって……","ENG":"W-well, you see... I happened to help some kids while looking for places, and they gave me this invitation as a thank-you gift...","TWN":"不，那個……我在路上幫了幾個孩子，然後他們作為答謝，給了我邀請函……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"그럼 외부 근무 중 무단이탈로 혼자 놀러 갔다는 소리잖아!","JPN":"つまり、外部勤務中に無断で遊びに行ったってことじゃないですか！","ENG":"Are you saying you left work, so you can have fun while everyone else is still working?","TWN":"這不就在說妳在外勤中擅自離開崗位，自己跑去玩了嗎！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_VOICE_NULL_NULL","text":{"KOREA":"그런 이야기를 이렇게 당당하게 해도 되는 거야! 이 모지리 계장님아!!","JPN":"よくもそんなことを堂々と！　係長、何を考えているんですか！","ENG":"How can you be so shameless? You're supposed to be a Chief!","TWN":"這種事情還說得這麼理所當然！妳這個笨科長！！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"미, 미안합니다......","JPN":"す、すみません……","ENG":"S-sorry...","TWN":"對、對不起……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"안~녕! 경찰 아가씨!","JPN":"こんにちは～！　警察のお姉さん！","ENG":"Hello, lady cop!","TWN":"哈~嘍！警察小姐！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"목소리 한 번 참 우렁차네요.","JPN":"すごく響く声ですね。","ENG":"You've got such a loud voice.","TWN":"妳嗓門可真大呢。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당신이 이번 블루로즈 섬 축제의 경비 요원인가요?","JPN":"あなたがブルーローズ祭の警備員ですか？","ENG":"Are you a security guard for the festival on Blue Rose Island?","TWN":"妳是這次藍玫瑰島慶典的警備人員？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"복장을 보면 딱히 경비 같진 않은데요?","JPN":"服装を見たところ、警備員とは到底思えませんが。","ENG":"You're not exactly dressed like one.","TWN":"看妳的服裝不像警衛啊？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"아, 그건 블루로즈 축제 규정이야! 여기선 직원들도 제복이 아니라 수영복을 입어야 하거든!","JPN":"あっ、それはブルーローズ祭のルールなの！　ここでは職員も全員、水着を着なきゃいけなくて！","ENG":"Oh, it's because of the Blue Rose festival rule. Everyone, even the employees, has to wear a swimsuit.","TWN":"啊，這是藍玫瑰慶典的規定！這裡的員工不穿制服，而是要穿泳裝！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"아 참! 난 조디악 나이츠의 리브 앨런이라고 해!","JPN":"あっ、そうそう！　私はゾディアックナイツのリブ・アレン！","ENG":"By the way, I'm Liv Allen, of the Zodiac Knights.","TWN":"對了！我是十二宮騎士團的莉芙·艾倫！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"조디악 나이츠라면 파견명단에서 봤어요. 태스크포스가 경비 일도 맡는 건가요?","JPN":"ゾディアックナイツなら派遣名簿で見ました。タスクフォースが警備の仕事も請け負っているのですか？","ENG":"I saw the Zodiac Knights on the dispatched personnel list. I didn't know TASKFORCE companies also take on security jobs.","TWN":"我在派遣名單上看到十二宮騎士團，特遣勢力還做警衛的工作嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"응! 축제기간에는 청원 경찰 외에 아카데미에서 추가로 경비 계약을 맺으니까.","JPN":"うん！　ブルーローズ祭は請願巡査以外にも、アカデミーで追加で警備契約をしてるから。","ENG":"Sure, the Academy hires additional security forces to assist you policemen during the festival.","TWN":"對啊！因為我們平時除了一般警備，在慶典期間，還會與學院簽署追加的警衛契約。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"블루로즈행 크루즈 경비 업무는 인기가 엄청 좋아서 다들 부러워했어.","JPN":"ブルーローズ行きのクルーズ船の警備はすごく人気で、みんな羨ましがってたよ！","ENG":"Everyone was envious of me for getting this Blue Rose cruise ship guard job, it's so popular.","TWN":"藍玫瑰遊輪的警衛工作人氣很高，大家都很羡慕我。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"우리 단장도 제비 뽑기에 실패하고는 앓아 누웠다니까?","JPN":"団長もくじ引きで負けて、寝込んじゃったんだ！","ENG":"My captain got bedridden after losing the draw to me.","TWN":"我們團長因為抽籤沒抽中後，懊惱得臥病在床呢。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐 그건 이쪽도 비슷하군요.","JPN":"まぁ、それはこっちも似たようなものです。","ENG":"Well, that sounds familiar.","TWN":"我們這裡也差不多。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시말서 쓰느라 파견이 취소된 파트너가 온갖 땡깡을 부리면서 경찰서 바닥을 데굴데굴 구르는 걸 말리느라 고생 좀 했거든요.","JPN":"始末書の作成で派遣が取り消されたパートナーが、\\n警察署の床を転がりまわって駄々をこねているのを止めるのに苦労しましたから。","ENG":"My partner couldn't come here because she had to write a letter of apology. I had to stop her from rolling on the floor, throwing a tantrum like a little child.","TWN":"我的同事因為要寫悔過書被取消了派遣，結果大鬧彆扭，在警察局的地板上滾來滾去，我費了好大的勁才讓她冷靜下來。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"같이 왔으면 좋았을 텐데 아쉽네! 여기 엄청 재밌다구!","JPN":"一緒に来れたら良かったのに残念だね！　ここすっごく面白いよ！","ENG":"It's a shame your partner couldn't be here. This place is lots of fun!","TWN":"如果能一起來就好了，好可惜喔！這裡那麼好玩！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당신, 경비 업무가 뭔지는 알고 있는 거겠죠?","JPN":"あなた、警備の任務が何かわかっていますよね？","ENG":"You do know what guard duty entails, right?","TWN":"妳，應該知道警衛工作是做什麼的吧？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"물론이지! 맡겨만 달라구!","JPN":"もちろん！　私に任せて！","ENG":"Of course! You just count on me!","TWN":"當然！交給我吧！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......어쨌든 무능력자 보다는 카운터가 더 도움이 되겠죠. 축제기간 동안 잘 부탁 드립니다.","JPN":"……とにかく、無能力者よりはカウンターの方が役に立つでしょう。\\nブルーローズ祭の間、よろしくお願いします。","ENG":"At least you're a Counter, and not those incompetent ordinary people. I'll count on you during the festival period.","TWN":"……制裁者應該比無能力者有用吧，那慶典期間就請多多指教了。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"나도 잘 부탁해!","JPN":"こちらこそよろしくね！","ENG":"Me, too!","TWN":"我也是，請多指教！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"으음, 잘 모르겠네요. 인간들의 축제에 참가해서 직접 즐거움을 느끼고 오라니......","JPN":"う～ん、よくわかりませんね。\\n人間たちのお祭りに参加して、直接楽しさというものを感じてこいだなんて……","ENG":"Mm, we're not sure why we should join this human festival and experience the type of fun they have...","TWN":"唔，真是不明白呢。竟然要我們去人類的慶典，親自享受樂趣……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"레지나 님도 너무하세요. 축제 같은 건 지식의 호수에도 흔히 있는 내용인데 말이죠.","JPN":"レジーナ様もひどいです。お祭りのようなものは知識の湖にもよくあるものだというのに。","ENG":"Miss Regina is so harsh. There's plenty of information about festivals in the Lake of Knowledge.","TWN":"蕾佳娜大人也太過分了，慶典這種東西，在知識之湖中也有很多共通的內容啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"게다가 이 숙녀답지 못한 차림은 뭘까요?","JPN":"それに、この淑女らしくない姿は何ですか？","ENG":"Worse still, what's up with this unladylike attire?","TWN":"而且這個一點都不淑女的衣服又是什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"앗, 그렇다고 벗으려고 하면 안돼요. 레지나 님이 직접 골라주신 거니까요.","JPN":"あっ、でも脱いではいけませんよ。レジーナさんが選んでくれたものなので。","ENG":"Ah, but we can't take it off. Miss Regina personally picked it for us.","TWN":"啊，別脫，是蕾佳娜大人親自挑選的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"그렇게 생각하면 오히려 기쁘게 입을 수 있는 걸요.","JPN":"そう思えば、むしろ嬉しいですね。","ENG":"Thinking that, we should be happy wearing it.","TWN":"既然這樣我們就好好穿著吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"하지만 아무리 그래도 배도 없이 직접 헤엄쳐서 섬으로 가야 한다니......","JPN":"でも、いくら何でも船も乗らずに自分で泳いで行かなければならないなんて……","ENG":"But she's making us swim all the way to the island instead of using a ship.","TWN":"但是，竟然要我們不搭船，直接游到島上……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"이 구멍투성이인 옷도 그렇고, 역시 저희를 해양생물의 일종으로 착각하신 게 아닐까요?","JPN":"この穴だらけの服もそうですし、やはり私たちを海洋生物の一種だと誤解しているのではないでしょうか？","ENG":"Look at these holey clothes. She has to have mistaken us for some aquatic creatures.","TWN":"還有這身到處都是洞的衣服也是，她該不會把我們當成某種海洋生物了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"하지만......","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"이제 와서 변덕 때문에 친애하는 부학회장님의 기대를 저버릴 순 없죠.","JPN":"今さら気まぐれで親愛なる副学会長様の期待を裏切るわけにはいきません。","ENG":"Still, we can't betray our beloved Vice President's expectations.","TWN":"事到如今，也不能因為自己一時興起，辜負親愛的副會長的期待。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"저희! 레지나님을 위해서 힘 내는 거에요!","JPN":"レジーナさんのために頑張りましょう！","ENG":"Come on, let's buck up for Miss Regina, shall we?","TWN":"我們！就為了蕾佳娜大人加油吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"어푸! 어푸!!","JPN":"あっぷ！　あっぷ！","ENG":"Poof! Poooffff!","TWN":"啊噗！啊噗！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                                           To be continued...","JPN":"                                                                                                           To be continued...","ENG":"                                                                                                           To be continued...","TWN":"To be continued……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_02"}]`);export{e as default};